import React, { useState, memo, FC } from 'react';
import Layout from '../../Layout/app/Layout';
import StepsUi from '../../Components/Cart/StepsUi';
import CartBody from '../../Components/Cart/CartBody';
import DetailsBody from '../../Components/Cart/DetailsBody';

interface CartPageProps {}

interface RenderPageContentProps {
  ViewPage: number;
  setViewPage: any;
}

const MemoizedStepsUi: FC<RenderPageContentProps> = memo(({ ViewPage, setViewPage }) => (
  <StepsUi ViewPage={ViewPage} setViewPage={setViewPage} />
));
const propsState = {}

const RenderPageContent: FC<RenderPageContentProps> = memo(({ ViewPage, setViewPage }) => {
  switch (ViewPage) {
    case 0:
      return <CartBody />;
    case 1:
      return <DetailsBody ViewPage={ViewPage} setViewPage={setViewPage} />;
    case 2:
      return <div>Page 3 content</div>;
    case 3:
      return <div>Page 4 content</div>;
    default:
      return null;
  }
});

const CartPage: FC<CartPageProps> = () => {
  const [ViewPage, setViewPage] = useState<number>(1);

  return (
    <Layout className='CartPage'>
      <MemoizedStepsUi ViewPage={ViewPage} setViewPage={setViewPage} />
      <RenderPageContent ViewPage={ViewPage} setViewPage={setViewPage} />
    </Layout>
  );
};

export default CartPage;
